export type Post = {
  id: number
  title: string
  content: string
}

let posts: Post[] = [
  { id: 1, title: 'Hello World', content: 'Welcome to the posts page!' },
  { id: 2, title: 'Second Post', content: 'This is another sample post.' },
]

export function getPosts(): Post[] {
  return posts
}

export function addPost(post: Omit<Post, 'id'>): Post {
  const newPost: Post = {
    id: posts.length > 0 ? Math.max(...posts.map((p) => p.id)) + 1 : 1,
    ...post,
  }
  posts = [...posts, newPost]
  return newPost
}

import { NextResponse } from 'next/server'
import { getPosts } from '@/lib/posts'

export async function GET() {
  const posts = getPosts()
  return NextResponse.json(posts)
}

'use server'

import { revalidateTag } from 'next/cache'
import { redirect } from 'next/navigation'
import { addPost } from '@/lib/posts'

export async function createPost(formData: FormData) {
  const title = formData.get('title')?.toString().trim()
  const content = formData.get('content')?.toString().trim()

  if (!title || !content) {
    throw new Error('Title and content are required')
  }

  addPost({ title, content })

  // Invalidate the 'posts' cache tag so the next page load
  // fetches fresh data instead of serving stale cached content.
  revalidateTag('posts')

  // Navigate back to the posts list, which triggers a server-side
  // re-render with up-to-date data.
  redirect('/')
}

import { headers } from 'next/headers'
import { createPost } from '@/app/actions'
import type { Post } from '@/lib/posts'

export default async function Home() {
  const headersList = await headers()
  const host = headersList.get('host') || 'localhost:3000'
  const protocol = headersList.get('x-forwarded-proto') || 'http'

  // Fetch posts via the API route with cache tagging so the
  // response is cached under the 'posts' tag.  When a Server
  // Action calls revalidateTag('posts'), this cache entry is
  // invalidated and the next request fetches fresh data.
  const res = await fetch(`${protocol}://${host}/api/posts`, {
    next: { tags: ['posts'] },
  })

  if (!res.ok) {
    throw new Error('Failed to fetch posts')
  }

  const posts: Post[] = await res.json()

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Posts</h1>

      <section
        style={{
          border: '1px solid #ddd',
          borderRadius: 8,
          padding: '1.25rem',
          marginBottom: '2rem',
          background: '#fafafa',
        }}
      >
        <h2 style={{ margin: '0 0 0.75rem', fontSize: '1.1rem' }}>Create a New Post</h2>
        <form action={createPost}>
          <div style={{ marginBottom: '0.75rem' }}>
            <label htmlFor="title" style={{ display: 'block', marginBottom: 4, fontWeight: 500 }}>
              Title
            </label>
            <input
              type="text"
              id="title"
              name="title"
              required
              placeholder="Post title"
              style={{ width: '100%', padding: '0.5rem', border: '1px solid #ccc', borderRadius: 4, boxSizing: 'border-box' }}
            />
          </div>
          <div style={{ marginBottom: '0.75rem' }}>
            <label htmlFor="content" style={{ display: 'block', marginBottom: 4, fontWeight: 500 }}>
              Content
            </label>
            <textarea
              id="content"
              name="content"
              required
              placeholder="Post content"
              rows={4}
              style={{ width: '100%', padding: '0.5rem', border: '1px solid #ccc', borderRadius: 4, boxSizing: 'border-box', resize: 'vertical' }}
            />
          </div>
          <button
            type="submit"
            style={{
              padding: '0.5rem 1.25rem',
              background: '#0070f3',
              color: '#fff',
              border: 'none',
              borderRadius: 4,
              cursor: 'pointer',
              fontWeight: 500,
            }}
          >
            Create Post
          </button>
        </form>
      </section>

      <section>
        <h2 style={{ margin: '0 0 0.75rem', fontSize: '1.1rem' }}>All Posts</h2>
        {posts.length === 0 ? (
          <p style={{ color: '#666' }}>No posts yet. Create one above!</p>
        ) : (
          <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
            {posts.map((post) => (
              <li
                key={post.id}
                style={{
                  padding: '1rem',
                  marginBottom: '0.75rem',
                  border: '1px solid #eee',
                  borderRadius: 8,
                }}
              >
                <strong style={{ fontSize: '1.05rem' }}>{post.title}</strong>
                <p style={{ margin: '0.25rem 0 0', color: '#444' }}>{post.content}</p>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  )
}

